// Copyrights belong to Discover Technologies LLC. © 2019 Discover Technologies LLC
// Script Continued Below
// 2.8.x | 2023-04-30 | raj  | STRY0138448 - Apply ACL to New Template/Template Subtask Form for Offices and Members in Private Structure
//RJ TEMPLATE PERMISSIONS UPDATE

// The filter was moved into the before business rule
// STRY0090875

// 2.7.1 | 2021-12-08 | raj  | DFCT0010613 - DEA: "Personal Template Designers" can view any template in the system
//               modified the code to turn the ACL back on and also apply the business rule query filter.
//               This way the user doesn't see the security constraints by default, but is locked out if they change the query.
//answer = true;

//STRY0138448
var primary_office = current.getValue('u_primary_office') || '';

 var allow = false;
 var UserPermissions  = new UserInfoScripts();
 allow = UserPermissions.userHasProcessRights(current);
// only check if allow comes back true from above
if(allow){
	allow = new task_privacy().userCanAccessOU(primary_office);
}
answer = allow;
